1	/**
2	 * OKKI 一键同步脚本
3	 *
4	 * 自动检测浏览器状态 → 登录 → 导航TM → 提取会话元数据 → 增量拉消息
5	 *
6	 * 用法：node scripts/sync_okki.js
7	 *
8	 * 适用所有场景：
9	 * - 刚开机/Chrome没开/没登录 → 自动启动Chrome → 等你登录 → 继续
10	 * - Chrome开着+已登录+在TM页 → 直接抓取
11	 * - Chrome开着但不在TM页 → 自动导航
12	 */
13	
14	const { chromium } = require('playwright');
15	const fs = require('fs');
16	const path = require('path');
17	const http = require('http');
18	
19	const PROFILE = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
20	const DATA_DIR = path.join(__dirname, '..', 'data');
21	const CHAT_DIR = path.join(DATA_DIR, 'chat_history');
22	const CDP_URL = 'http://localhost:9222';
23	const MSG_COUNT = 50;
24	const MAX_PAGES = 20;
25	
26	// ===================== 工具函数 =====================
27	
28	function ts() { return new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19); }
29	function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }
30	function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
31	
32	function sanitizeFilename(cid) {
33	  return cid.replace(/[<>:"/\\|?*#@]/g, '_').substring(0, 200);
34	}
35	
36	// ===================== CDP 端口检测 =====================
37	
38	function checkCdpPort() {
39	  return new Promise((resolve) => {
40	    const req = http.get('http://127.0.0.1:9222/json/version', (res) => {
41	      let data = '';
42	      res.on('data', c => data += c);
43	      res.on('end', () => {
44	        try {
45	          const json = JSON.parse(data);
46	          resolve(!!json.webSocketDebuggerUrl);
47	        } catch (e) { resolve(false); }
48	      });
49	    });
50	    req.on('error', () => resolve(false));
51	    req.setTimeout(2000, () => { req.destroy(); resolve(false); });
52	  });
53	}
54	
55	// ===================== 主流程 =====================
56	
57	async function main() {
58	  let browser;
59	  let page;
60	  let useCdp = false;
61	
62	  // ---- Step 1: 启动/连接浏览器 ----
63	  const cdpAvailable = await checkCdpPort();
64	  if (cdpAvailable) {
65	    log('检测到 CDP 端口，尝试连接已有 Chrome...');
66	    try {
67	      browser = await chromium.connectOverCDP(CDP_URL);
68	      const pages = browser.contexts()[0]?.pages() || [];
69	      page = pages.find(p => p.url().includes('xiaoman') || p.url().includes('onetalk'));
70	      if (!page) {
71	        page = await browser.contexts()[0].newPage();
72	      }
73	      useCdp = true;
74	      log(`CDP 已连接。当前页面: ${page.url()}`);
75	    } catch (e) {
76	      log(`CDP 连接失败: ${e.message}，改用独立启动模式`);
77	    }
78	  }
79	
80	  if (!browser) {
81	    log('启动 Chrome (Profile 4)...');
82	    browser = await chromium.launchPersistentContext(PROFILE, {
83	      channel: 'chrome',
84	      headless: false,
85	      viewport: { width: 1440, height: 900 },
86	      args: ['--remote-debugging-port=9222'],
87	    });
88	    page = await browser.newPage();
89	    log('Chrome 已启动');
90	  }
91	
92	  // ---- Step 2: 导航到 OKKI + 登录检测 ----
93	  const currentUrl = page.url();
94	  if (!currentUrl.includes('xiaoman') && !currentUrl.includes('onetalk') && !currentUrl.includes('alibaba')) {
95	    log('导航到 crm.xiaoman.cn...');
96	    await page.goto('https://crm.xiaoman.cn/', { waitUntil: 'domcontentloaded', timeout: 30000 });
97	  }
98	
99	  // 检测登录状态
100	  let loginUrl = page.url();
101	  if (loginUrl.includes('login.xiaoman.cn') || loginUrl.includes('login.alibaba.com')) {
102	    log('');
103	    log('========================================');
104	    log('  请在浏览器中登录 OKKI (小满)');
105	    log('  登录后脚本自动继续...');
106	    log('========================================');
107	    log('');
108	
109	    const startTime = Date.now();
110	    const maxWait = 5 * 60 * 1000;
111	    while (Date.now() - startTime < maxWait) {
112	      const url = page.url();
113	      if (!url.includes('login.xiaoman.cn') && !url.includes('login.alibaba.com') && url.includes('crm.xiaoman.cn')) {
114	        log('登录成功！');
115	        break;
116	      }
117	      await sleep(2000);
118	    }
119	    if (page.url().includes('login')) {
120	      log('超时：未检测到登录。退出。');
121	      await browser.close();
122	      process.exit(1);
123	    }
124	  } else {
125	    log('已登录状态');
126	  }
127	
128	  // ---- Step 3: 导航到 TM 消息页面 ----
129	  log('导航到 TM 消息页...');
130	  await page.goto('https://crm.xiaoman.cn/im/', { waitUntil: 'domcontentloaded', timeout: 30000 }).catch(() => {});
131	  await sleep(3000);
132	
133	  // 可能需要点击侧边栏进入 TM（OKKI 的 /im/ 可能只显示外壳，onetalk 在 iframe 里）
134	  log(`当前 URL: ${page.url()}`);
135	
136	  // ---- Step 4: 等待 onetalk iframe + 数据就绪 ----
137	  log('等待 onetalk iframe 加载...');
138	
139	  // 递归查找 onetalk 页面（可能在嵌套 iframe 中）
140	  function findOnetalkFrame(pageOrFrame) {
141	    const frames = pageOrFrame.frames ? pageOrFrame.frames() : (pageOrFrame.childFrames ? pageOrFrame.childFrames() : []);
142	    for (const f of frames) {
143	      const url = f.url();
144	      // 真正的 onetalk PWA 页面，不是 OKKI 外壳
145	      if (url.startsWith('https://onetalk.alibaba.com/')) return f;
146	      // 递归查找
147	      const found = findOnetalkFrame(f);
148	      if (found) return found;
149	    }
150	    return null;
151	  }
152	
153	  let iframePage = null;
154	  for (let attempt = 0; attempt < 30; attempt++) {
155	    iframePage = findOnetalkFrame(page);
156	    if (iframePage) {
157	      log(`onetalk iframe 已找到 (尝试 ${attempt + 1}): ${iframePage.url().slice(0, 100)}`);
158	      break;
159	    }
160	    if (attempt === 0) {
161	      const bodyText = await page.evaluate(() => document.body.innerText?.slice(0, 500)).catch(() => '');
162	      log(`  页面预览: ${bodyText.slice(0, 200)}`);
163	      // 检查是否在 OKKI 外壳中
164	      const allFrames = page.frames();
165	      log(`  当前 ${allFrames.length} 个 frame:`);
166	      for (const f of allFrames) {
167	        log(`    ${f.url().slice(0, 120)}`);
168	      }
169	    }
170	    await sleep(2000);
171	  }
172	
173	  if (!iframePage) {
174	    log('iframe 未找到。请确认：');
175	    log('  1. 已退出手机阿里卖家');
176	    log('  2. OKKI TM 面板不是 "Click to retry" 状态');
177	    log('  3. TM 面板中能看到会话列表');
178	    log('');
179	    log('脚本保持运行。完成上述操作后回车继续...');
180	    await new Promise(() => {});
181	  }
182	
183	  // ---- Step 4.5: 滚动加载全部会话 ----
184	  // 虚拟列表只渲染可见窗口，不滚动会漏掉窗口外的新客户/老客户
185	  log('滚动加载全部会话...');
186	  let initialCount = await iframePage.evaluate(() => (window.__conversationListFullData__ || []).length);
187	  log(`  初始会话数: ${initialCount}`);
188	
189	  let lastCount = initialCount;
190	  let unchangedRounds = 0;
191	
192	  for (let round = 0; round < 50; round++) {
193	    const scrollResult = await iframePage.evaluate(() => {
194	      let best = null;
195	      let bestScore = 0;
196	      for (const el of document.querySelectorAll('div')) {
197	        const childCount = el.children.length;
198	        const scrollDiff = el.scrollHeight - el.clientHeight;
199	        if (childCount > 20 && scrollDiff > 200) {
200	          const score = childCount + scrollDiff;
201	          if (score > bestScore) { best = el; bestScore = score; }
202	        }
203	      }
204	      if (!best) return { done: true, count: (window.__conversationListFullData__ || []).length };
205	      const before = (window.__conversationListFullData__ || []).length;
206	      best.scrollTop = best.scrollHeight;
207	      return { done: false, before, scrollH: best.scrollHeight, clientH: best.clientHeight };
208	    });
209	
210	    if (scrollResult.done) { log('  找不到合适的滚动容器'); break; }
211	    await sleep(2000);
212	
213	    const newCount = await iframePage.evaluate(() => (window.__conversationListFullData__ || []).length);
214	    if (round % 3 === 0 || newCount !== lastCount) {
215	      log(`  第${round+1}轮: ${scrollResult.before} → ${newCount}`);
216	    }
217	
218	    if (newCount === lastCount) {
219	      unchangedRounds++;
220	      // scrollTop 可能不触发虚拟列表渲染，改用 mouse.wheel 兜底
221	      if (unchangedRounds === 1) {
222	        await iframePage.mouse.wheel(0, 9999);
223	        await sleep(2000);
224	      }
225	      if (unchangedRounds >= 3) { log('  数据已稳定，滚动完成'); break; }
226	    } else {
227	      unchangedRounds = 0;
228	    }
229	    lastCount = newCount;
230	  }
231	
232	  const finalCount = await iframePage.evaluate(() => (window.__conversationListFullData__ || []).length);
233	  log(`  滚动后会话总数: ${finalCount} (初始: ${initialCount})`);
234	
235	  // ---- Step 5: 提取会话列表（带重试） ----
236	  log('提取会话元数据...');
237	  let convData = null;
238	  for (let attempt = 0; attempt < 20; attempt++) {
239	    convData = await iframePage.evaluate(() => {
240	      const convs = window.__conversationListFullData__;
241	      if (!convs || !Array.isArray(convs)) return { error: 'no __conversationListFullData__', type: typeof convs, count: 0 };
242	      return {
243	        count: convs.length,
244	        list: convs.map(c => ({
245	          cid: c.cid,
246	          name: c.name,
247	          loginId: c.loginId,
248	          aliId: c.aliId,
249	          accountId: c.accountId,
250	          companyName: c.companyName,
251	          country: c.country,
252	          level: c.level,
253	          serviceType: c.serviceType,
254	          conversationType: c.conversationType,
255	          unreadCount: c.unreadCount,
256	          stayTop: c.stayTop,
257	          lastContactTime: c.lastContactTime,
258	          lastContactTimeLong: c.lastContactTimeLong,
259	          createAt: c.createAt,
260	          tagInfo: c.tagInfo,
261	          available: c.available,
262	          complianceCountryCode: c.complianceCountryCode,
263	          latestMessage: c.latestMessage ? {
264	            content: c.latestMessage.content,
265	            messageType: c.latestMessage.messageType,
266	            messageId: c.latestMessage.messageId,
267	            gmtChat: c.latestMessage.gmtChat,
268	            contactRead: c.latestMessage.contactRead,
269	          } : null,
270	        })),
271	      };
272	    }).catch(e => ({ error: e.message, count: 0 }));
273	
274	    if (!convData.error && convData.count > 0) {
275	      log(`提取成功: ${convData.count} 个会话 (尝试 ${attempt + 1})`);
276	      break;
277	    }
278	    if (attempt === 0) {
279	      log(`  等待 TM 数据加载 (${convData.error || '空数据'})...`);
280	    }
281	    await sleep(2000);
282	  }
283	
284	  if (!convData || convData.error || convData.count === 0) {
285	    log(`提取失败: ${convData?.error || '无数据'}`);
286	    log('TM 面板可能未正常加载。请确认能看到会话列表后重新运行脚本。');
287	    await browser.close();
288	    process.exit(1);
289	  }
290	
291	  // 展平结果
292	  const convList = convData.list;
293	  const totalCount = convData.count;
294	
295	  log(`提取到 ${totalCount} 个会话`);
296	
297	  // 加载 master.json（累积全集）
298	  const masterPath = path.join(DATA_DIR, 'tm_conversations_master.json');
299	  let masterMap = new Map();
300	  let masterPrevMax = 0;
301	  if (fs.existsSync(masterPath)) {
302	    try {
303	      const master = JSON.parse(fs.readFileSync(masterPath, 'utf-8'));
304	      for (const c of master.conversations) {
305	        masterMap.set(c.cid, c);
306	      }
307	      masterPrevMax = master.conversations.length;
308	    } catch (e) { /* master 损坏则重建 */ }
309	  }
310	  log(`master.json 已有 ${masterMap.size} 条历史记录`);
311	
312	  // ---- Step 6: 保存最新元数据 ----
313	  const latestMeta = {
314	    exportedAt: new Date().toISOString(),
315	    total: totalCount,
316	    conversations: convList,
317	  };
318	  const metaPath = path.join(DATA_DIR, 'tm_conversations_latest.json');
319	  fs.writeFileSync(metaPath, JSON.stringify(latestMeta, null, 2));
320	  log(`元数据已保存: tm_conversations_latest.json (${totalCount} 会话)`);
321	
322	  // ---- Step 7: Diff 找出变化的会话 ----
323	  log('对比上次数据...');
324	  let oldMeta = null;
325	  const oldPath = path.join(DATA_DIR, 'tm_conversations_full.json');
326	  if (fs.existsSync(oldPath)) {
327	    oldMeta = JSON.parse(fs.readFileSync(oldPath, 'utf-8'));
328	  }
329	
330	  const changed = [];
331	  const oldMap = new Map();
332	  if (oldMeta?.conversations) {
333	    for (const c of oldMeta.conversations) {
334	      oldMap.set(c.cid, c);
335	    }
336	  }
337	
338	  for (const c of convList) {
339	    const old = oldMap.get(c.cid);
340	    if (!old) {
341	      // 新会话
342	      changed.push({ cid: c.cid, name: c.name, reason: '新会话', oldLmId: null, newLmId: c.latestMessage?.messageId });
343	      continue;
344	    }
345	    const oldLmId = old.latestMessage?.messageId;
346	    const newLmId = c.latestMessage?.messageId;
347	    const oldLct = old.lastContactTime || 0;
348	    const newLct = c.lastContactTime || 0;
349	
350	    if (oldLmId !== newLmId || newLct > oldLct) {
351	      const reason = oldLmId !== newLmId ? '消息更新' : '时间更新';
352	      changed.push({ cid: c.cid, name: c.name, reason, oldLmId, newLmId });
353	    }
354	  }
355	
356	  log(`变化会话: ${changed.length} 个`);
357	  if (changed.length > 0) {
358	    for (const ch of changed.slice(0, 15)) {
359	      log(`  ${ch.reason}: ${ch.name}`);
360	    }
361	    if (changed.length > 15) log(`  ... 共 ${changed.length} 个`);
362	  }
363	
364	  // ---- Step 8: 增量拉取聊天历史 ----
365	  if (changed.length === 0) {
366	    log('无变化，无需拉取聊天历史。同步完成。');
367	    computePreComputed(convList);
368	    printSummary(convList, changed);
369	    log('浏览器保持打开，供后续脚本使用');
370	    return;
371	  }
372	
373	  log('');
374	  log(`开始增量拉取 ${changed.length} 个会话的聊天历史...`);
375	
376	  // 获取 CDP session
377	  let cdpClient;
378	  let iframeSessionId;
379	
380	  if (!useCdp) {
381	    // Playwright 启动模式: 需要通过 CDP 访问 iframe
382	    cdpClient = await page.context().newCDPSession(page);
383	    const targets = await cdpClient.send('Target.getTargets');
384	    const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
385	    if (ot) {
386	      const attached = await cdpClient.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });
387	      iframeSessionId = attached.sessionId;
388	      log(`CDP attached to onetalk iframe: ${ot.url.slice(0, 80)}`);
389	    } else {
390	      log('警告: 未找到 onetalk iframe target，尝试用 page.frames() 方式...');
391	    }
392	  } else {
393	    // CDP 连接模式: page 已经是 CDP 连接的
394	    cdpClient = await page.context().newCDPSession(page);
395	    const targets = await cdpClient.send('Target.getTargets');
396	    const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
397	    if (!ot) {
398	      // 检查 page 本身是否是 onetalk
399	      if (page.url().includes('onetalk')) {
400	        iframeSessionId = undefined; // page 本身就是 onetalk
401	        log('当前页面就是 onetalk');
402	      } else {
403	        log('警告: 未找到 onetalk target');
404	      }
405	    } else {
406	      const attached = await cdpClient.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });
407	      iframeSessionId = attached.sessionId;
408	      log(`CDP attached to onetalk iframe`);
409	    }
410	  }
411	
412	  // 安装 LWP 收发器
413	  if (iframeSessionId || page.url().includes('onetalk')) {
414	    log('安装 LWP 收发器...');
415	    await installLwp(cdpClient, iframeSessionId);
416	    await sleep(3000);
417	
418	    // 确认 WS 已捕获
419	    const wsState = await evalInIframe(cdpClient, iframeSessionId, 10,
420	      `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`
421	    );
422	    log(`WS 状态: ${JSON.stringify(wsState)}`);
423	
424	    if (!wsState?.ws) {
425	      log('等待 WebSocket 连接...');
426	      await sleep(15000);
427	      const wsState2 = await evalInIframe(cdpClient, iframeSessionId, 11,
428	        `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`
429	      );
430	      log(`WS 状态(重试): ${JSON.stringify(wsState2)}`);
431	    }
432	
433	    // 拉取消息
434	    let pulled = 0;
435	    let errors = 0;
436	    let totalNewMsgs = 0;
437	    let msgIdCounter = 100;
438	
439	    for (let i = 0; i < changed.length; i++) {
440	      const conv = changed[i];
441	      try {
442	        const allMessages = [];
443	        let cursor = 9007199254740991;
444	        let pageNum = 0;
445	
446	        while (pageNum < MAX_PAGES) {
447	          const msgId = msgIdCounter++;
448	          const raw = await evalInIframe(cdpClient, iframeSessionId, msgId,
449	            `(async function() {
450	              try {
451	                var result = await window.__lwpRequest('/r/MessageManager/listUserMessages', ['${conv.cid}', false, ${cursor}, ${MSG_COUNT}, false]);
452	                return JSON.stringify(result);
453	              } catch(e) {
454	                return JSON.stringify({ __error: e.message });
455	              }
456	            })()`,
457	            true
458	          );
459	
460	          await sleep(1500);
461	
462	          if (!raw || raw.__error) {
463	            if (raw?.__error === 'timeout') { log(`  [${conv.name}] LWP超时`); }
464	            break;
465	          }
466	
467	          let response;
468	          try { response = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { break; }
469	          if (response.code !== 200) break;
470	
471	          const body = response.body;
472	          if (!body?.userMessageModels || body.userMessageModels.length === 0) break;
473	
474	          allMessages.push(...body.userMessageModels);
475	
476	          if (body.userMessageModels.length < MSG_COUNT || !body.nextCursor) break;
477	          cursor = body.nextCursor;
478	          pageNum++;
479	        }
480	
481	        // 保存
482	        const safeName = sanitizeFilename(conv.cid);
483	        const output = {
484	          cid: conv.cid,
485	          name: conv.name,
486	          fetchedAt: new Date().toISOString(),
487	          totalMessages: allMessages.length,
488	          messages: allMessages,
489	        };
490	        fs.writeFileSync(path.join(CHAT_DIR, safeName + '.json'), JSON.stringify(output, null, 2));
491	        pulled++;
492	        totalNewMsgs += allMessages.length;
493	        if (allMessages.length > 0) {
494	          log(`  [${i+1}/${changed.length}] ${conv.name}: ${allMessages.length} 条消息`);
495	        }
496	      } catch (e) {
497	        errors++;
498	        if (errors <= 5) log(`  [${conv.name}] 错误: ${e.message}`);
499	      }
500	    }
501	
502	    log(`拉取完成: ${pulled} 个会话, ${totalNewMsgs} 条消息, ${errors} 个错误`);
503	  } else {
504	    log('');
505	    log('========================================');
506	    log('  ❌ LWP 拉取失败：无法访问 onetalk iframe');
507	    log('  请确认：');
508	    log('  1. Chrome 已打开 OKKI TM 面板');
509	    log('  2. TM 面板中能看到会话列表');
510	    log('  3. 没有其他程序占用 CDP 端口 9222');
511	    log('========================================');
512	    log('');
513	    log('脚本退出。请排查后重新运行。');
514	    process.exit(1);
515	  }
516	
517	  // ---- Step 9: 预计算 + master合并 + 归档 + 输出摘要 ----
518	  computePreComputed(convList);
519	
520	  // Master 合并：将本次抓取结果合并到累积全集
521	  const today = new Date().toISOString().slice(0, 10);
522	  const seenCids = new Set();
523	  for (const c of convList) {
524	    seenCids.add(c.cid);
525	    const existing = masterMap.get(c.cid);
526	    if (existing) {
527	      // 更新字段但保留最早的 firstSeenAt
528	      c.lastSeenAt = today;
529	      c.firstSeenAt = existing.firstSeenAt || existing.lastSeenAt || today;
530	      masterMap.set(c.cid, Object.assign(existing, c));
531	    } else {
532	      c.lastSeenAt = today;
533	      c.firstSeenAt = today;
534	      masterMap.set(c.cid, c);
535	    }
536	  }
537	  // 本次未出现的客户保留在 master，lastSeenAt 不变（自然老化）
538	
539	  // 数量异常检测
540	  if (masterPrevMax > 0 && convList.length < masterPrevMax * 0.9) {
541	    console.log(`⚠️  本次抓取 ${convList.length} 会话，低于历史峰值 ${masterPrevMax}（${Math.round(convList.length/masterPrevMax*100)}%），可能有遗漏`);
542	  }
543	
544	  const masterConversations = Array.from(masterMap.values());
545	  const masterMeta = {
546	    exportedAt: new Date().toISOString(),
547	    total: masterConversations.length,
548	    conversations: masterConversations,
549	  };
550	  fs.writeFileSync(masterPath, JSON.stringify(masterMeta, null, 2));
551	  log(`已写入 master.json (${masterConversations.length} 条累积记录)`);
552	
553	  // 从 master 生成 active 子集（最近7天出现过的客户）
554	  const sevenDaysAgo = new Date(Date.now() - 7 * 86400000).toISOString().slice(0, 10);
555	  const activeConversations = masterConversations.filter(c => (c.lastSeenAt || '') >= sevenDaysAgo);
556	  const activeMeta = {
557	    exportedAt: new Date().toISOString(),
558	    total: activeConversations.length,
559	    conversations: activeConversations,
560	    _source: 'master.json active subset (7-day window)',
561	  };
562	  const metaPath2 = path.join(DATA_DIR, 'tm_conversations_latest.json');
563	  fs.writeFileSync(metaPath2, JSON.stringify(activeMeta, null, 2));
564	  log(`已写入 tm_conversations_latest.json (${activeConversations.length} 活跃会话)`);
565	
566	  // 归档基线（用于下次 diff）：从 master 生成
567	  const fullPath = path.join(DATA_DIR, 'tm_conversations_full.json');
568	  fs.writeFileSync(fullPath, JSON.stringify(activeMeta, null, 2));
569	  log('已归档基线: tm_conversations_full.json');
570	
571	  // 写同步标记
572	  const newCount = seenCids.size - (masterPrevMax || seenCids.size);
573	  const syncMarker = {
574	    date: today,
575	    count: convList.length,
576	    masterTotal: masterConversations.length,
577	    activeCount: activeConversations.length,
578	    newConversations: Math.max(0, convList.length - masterPrevMax),
579	    updatedConversations: changed.filter(c => c.reason !== '新会话').length,
580	    source: 'sync_okki.js',
581	  };
582	  fs.writeFileSync(path.join(DATA_DIR, '.last_sync.json'), JSON.stringify(syncMarker, null, 2));
583	
584	  printSummary(convList, changed);
585	  log('同步完成。浏览器保持打开，供后续脚本使用');
586	}
