588	// ===================== LWP 工具 =====================
589	
590	async function installLwp(cdpClient, iframeSessionId) {
591	  const expr = `
592	    (function() {
593	      var _send = WebSocket.prototype.send;
594	      var _ae = WebSocket.prototype.addEventListener;
595	
596	      window.__lwpPending = {};
597	      window.__lwpSeq = 0;
598	
599	      WebSocket.prototype.send = function(data) {
600	        if (!window.__lwpWs && this.readyState === 1) {
601	          window.__lwpWs = this;
602	          _ae.call(this, 'message', function(event) {
603	            try {
604	              var raw = typeof event.data === 'string' ? event.data : '';
605	              if (raw.indexOf('"code"') < 0) return;
606	              var parsed = JSON.parse(raw);
607	              var mid = parsed.headers && parsed.headers.mid;
608	              if (mid && window.__lwpPending[mid]) {
609	                var p = window.__lwpPending[mid];
610	                delete window.__lwpPending[mid];
611	                p.resolve(parsed);
612	              }
613	            } catch(e) {}
614	          });
615	          console.log('[LWP] WS captured: ' + this.url);
616	        }
617	        return _send.call(this, data);
618	      };
619	
620	      window.__lwpRequest = function(lwpPath, body) {
621	        return new Promise(function(resolve, reject) {
622	          var ws = window.__lwpWs;
623	          if (!ws || ws.readyState !== 1) { reject(new Error('WS not ready')); return; }
624	          var mid = Date.now() + ' ' + (++window.__lwpSeq);
625	          var req = JSON.stringify({ lwp: lwpPath, headers: { mid: mid }, body: body });
626	          window.__lwpPending[mid] = { resolve: resolve, reject: reject };
627	          ws.send(req);
628	          setTimeout(function() {
629	            if (window.__lwpPending[mid]) { delete window.__lwpPending[mid]; reject(new Error('timeout')); }
630	          }, 30000);
631	        });
632	      };
633	
634	      return JSON.stringify({ installed: true });
635	    })()
636	  `;
637	
638	  return sendToTarget(cdpClient, iframeSessionId, 3, expr);
639	}
