683	
684	const SYSTEM_MSG_PATTERNS = [
685	  '自动接待将不再触发',
686	  'Since you have read the conversation',
687	  'Marco大模型翻译',
688	  '阿里国际Marco大模型翻译',
689	  '买家有流失风险',
690	  'Buyer has churn risk',
691	  '一旦离开平台发生纠纷或欺诈',
692	  '由于您介入该会话',
693	  'Due to your intervention in this session',
694	  'AI给您生成了一条回复建议',
695	  'You have a visitor',
696	  'This buyer has been pre-screened',
697	  '平台规则提醒', '为了更好的保护买卖双方利益', '维护平台有序的市场秩序', '引导买家站外沟通',
698	];
