700	function computePreComputed(convList) {
701	  const now = Date.now();
702	  const chatDir = path.join(DATA_DIR, 'chat_history');
703	
704	  for (const c of convList) {
705	    c.preComputed = {};
706	
707	    // 1. 是否未读
708	    c.preComputed.isUnread = (c.unreadCount || 0) > 0;
709	
710	    // 2. 距上次联系天数
711	    const lct = c.lastContactTimeLong || c.lastContactTime || 0;
712	    c.preComputed.daysSinceLastContact = lct > 0 ? Math.floor((now - lct) / 86400000) : null;
713	
714	    // 3. latestMessage 是否是系统消息
715	    const lmContent = c.latestMessage?.content || '';
716	    c.preComputed.isLatestMessageSystem = false;
717	    if (lmContent) {
718	      for (const pat of SYSTEM_MSG_PATTERNS) {
719	        if (lmContent.includes(pat)) {
720	          c.preComputed.isLatestMessageSystem = true;
721	          break;
722	        }
723	      }
724	    }
725	
726	    // 4. 是否有 chat_history 文件
727	    const fileName = sanitizeFilename(c.cid) + '.json';
728	    const filePath = path.join(chatDir, fileName);
729	    c.preComputed.hasChatHistoryFile = fs.existsSync(filePath);
730	
731	    // 5. 是否有真实消息（chat_history 文件中存在非系统消息）
732	    c.preComputed.hasRealMessages = false;
733	    if (c.preComputed.hasChatHistoryFile) {
734	      try {
735	        const data = JSON.parse(fs.readFileSync(filePath, 'utf-8'));
736	        for (const msg of (data.messages || [])) {
737	          const content = msg.message?.content?.text?.content || '';
738	          if (!content) continue;
739	          let isSys = false;
740	          for (const pat of SYSTEM_MSG_PATTERNS) {
741	            if (content.includes(pat)) { isSys = true; break; }
742	          }
743	          if (!isSys) {
744	            c.preComputed.hasRealMessages = true;
745	            break;
746	          }
747	        }
748	      } catch (e) {}
749	    }
750	  }
751	
752	  // 重新保存带 preComputed 的元数据
753	  const metaPath = path.join(DATA_DIR, 'tm_conversations_latest.json');
754	  const latestMeta = {
755	    exportedAt: new Date().toISOString(),
756	    total: convList.length,
757	    conversations: convList,
758	  };
759	  fs.writeFileSync(metaPath, JSON.stringify(latestMeta, null, 2));
760	  log(`preComputed 已计算，元数据已更新`);
761	}
