const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = await browser.contexts()[0].newPage();

  // 先去主页，获取cookies和认证
  await page.goto('https://crm.xiaoman.cn/', { waitUntil: 'domcontentloaded', timeout: 15000 }).catch(() => {});
  await new Promise(r => setTimeout(r, 2000));

  // 直接用fetch拦截方式捕获API响应
  let leadsApiResponses = [];
  page.on('response', async (resp) => {
    const url = resp.url();
    if (url.includes('lead') || url.includes('inquiry') || url.includes('alibabaRead')) {
      try {
        const body = await resp.text();
        leadsApiResponses.push({ url: url.slice(0,150), status: resp.status(), body: body.slice(0,500) });
      } catch(e) {}
    }
  });

  // 尝试点击 OKKI Leads 菜单
  console.log('点击 OKKI Leads 菜单...');
  await page.evaluate(() => {
    const links = document.querySelectorAll('a, div, span, li');
    for (const el of links) {
      if (el.textContent.includes('Leads') || el.textContent.includes('线索')) {
        el.click();
        break;
      }
    }
  });

  await new Promise(r => setTimeout(r, 5000));
  console.log('Current URL:', page.url());

  // 检查页面文本
  const body = await page.evaluate(() => document.body.innerText.slice(0, 1000));
  console.log('Body:', body.slice(0, 800));

  // 报告捕获到的API响应
  console.log('---');
  console.log('Captured API responses:', leadsApiResponses.length);
  for (const r of leadsApiResponses) {
    console.log(r.url, r.status, r.body.slice(0,200));
  }

})();
