const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const pages = browser.contexts()[0].pages();
  let page = pages.find(p => p.url().includes('crm.xiaoman.cn') && !p.url().includes('404'));

  // 用 Playwright 的 APIRequest 来调，这样绕过 CSP
  const context = page.context();

  // 先从浏览器拿 cookies
  const cookies = await context.cookies();
  const cookieHeader = cookies.map(c => c.name + '=' + c.value).join('; ');

  // 用 node fetch 试
  const https = require('https');
  const http = require('http');

  function apiGet(urlPath) {
    return new Promise((resolve) => {
      const options = {
        hostname: 'crm.xiaoman.cn',
        path: urlPath,
        headers: {
          'Cookie': cookieHeader,
          'Accept': 'application/json',
          'x-requested-with': 'XMLHttpRequest'
        },
        timeout: 10000
      };
      const req = https.get(options, (res) => {
        let data = '';
        res.on('data', c => data += c);
        res.on('end', () => {
          resolve({ status: res.statusCode, body: data.slice(0, 500) });
        });
      });
      req.on('error', (e) => resolve({ error: e.message }));
      req.on('timeout', () => { req.destroy(); resolve({ error: 'timeout' }); });
    });
  }

  // 测试各种 API
  const apis = [
    '/api/leadRead/unReadCount',
    '/api/alibabaRead/unReadList',
    '/api/leadRead/list?pageNo=1&pageSize=5',
    '/api/lead/private/list?pageNo=1&pageSize=5',
    '/api/leads-api/lead/list?pageNo=1&pageSize=5',
    '/api/inquiry/list?pageNo=1&pageSize=5',
    '/api/lead/inquiry/list?pageNo=1&pageSize=5',
    '/api/alibaba/inquiry/list?pageNo=1&pageSize=5',
    '/api/leads/list?pageNo=1&pageSize=5',
  ];

  for (const api of apis) {
    const r = await apiGet(api);
    const label = r.status ? (r.status + '') : 'ERR';
    const body = r.body || r.error || '';
    console.log(api + ' → ' + label + ' | ' + body.slice(0, 200));
  }

})();
" 2>&1

