const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const pages = browser.contexts()[0].pages();
  let page = pages.find(p => p.url().includes('crm.xiaoman.cn') && !p.url().includes('404'));

  console.log('Current URL:', page.url());

  // 查找 OKKI Leads 菜单的DOM
  const leadsInfo = await page.evaluate(() => {
    const result = [];
    // 找侧边栏所有可点击元素
    const allEls = document.querySelectorAll('a, li, [class*=menu], [class*=nav], [class*=side]');
    for (const el of allEls) {
      const text = el.textContent?.trim();
      if (text && (text.includes('Leads') || text.includes('lead') || text.includes('线索'))) {
        result.push({
          tag: el.tagName,
          text: text.slice(0, 100),
          href: el.getAttribute('href') || el.getAttribute('to') || '',
          class: el.className?.slice(0, 150) || '',
          onclick: !!el.onclick,
          dataAttrs: Object.keys(el.dataset || {}).join(','),
          routerLink: el.getAttribute('data-v-') || '',
        });
      }
    }
    return result;
  });
  console.log('Leads menu elements:', JSON.stringify(leadsInfo, null, 2));

  // 也查一下 SPARouter 的路由表
  const routes = await page.evaluate(() => {
    if (window.__SPA_ROUTER) {
      return window.__SPA_ROUTER.options?.routes?.map(r => r.path) || [];
    }
