const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const pages = browser.contexts()[0].pages();
  let page = pages.find(p => p.url().includes('crm.xiaoman.cn') && !p.url().includes('404'));

  // 监控所有 lead/inquiry 相关 API
  const apis = [];
  page.on('response', async (resp) => {
    const url = resp.url();
    if (url.includes('lead') || url.includes('inquiry') || url.includes('alibaba') || url.includes('hunter')) {
      try {
        const body = await resp.text();
        apis.push({ url: url, status: resp.status(), body: body.slice(0, 800) });
      } catch(e) {}
    }
  });

  // 点击 OKKI Leads li
  console.log('点击 OKKI Leads...');
  const clicked = await page.evaluate(() => {
    const lis = document.querySelectorAll('li');
    for (const li of lis) {
      if (li.textContent.trim() === 'OKKI Leads') {
        li.click();
        return true;
      }
    }
    return false;
  });
  console.log('Clicked:', clicked);

  await new Promise(r => setTimeout(r, 8000));
  console.log('New URL:', page.url());

  // 查看当前页面内容
  const body = await page.evaluate(() => document.body.innerText.slice(0, 2000));
  console.log('Body preview:', body.slice(0, 1200));

  console.log('---');
  console.log('Captured APIs:', apis.length);
  for (const a of apis) {
    console.log(a.url.slice(0,120), a.status, a.body.slice(0,300));
  }

})();
" 2>&1

