const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const page = await browser.contexts()[0].newPage();

  // 导航到 TM 页面
  await page.goto('https://crm.xiaoman.cn/im/', { waitUntil: 'domcontentloaded', timeout: 15000 }).catch(() => {});
  await new Promise(r => setTimeout(r, 5000));

  console.log('URL:', page.url());

  // 找 onetalk frame
  function findOT(p) {
    for (const f of (p.frames ? p.frames() : [])) {
      if (f.url().startsWith('https://onetalk.alibaba.com/')) return f;
      const r = findOT(f);
      if (r) return r;
    }
    return null;
  }

  const ot = findOT(page);
  if (!ot) {
    console.log('onetalk not found. Frames:');
    for (const f of page.frames()) console.log(' ', f.url().slice(0,120));
    return;
  }
  console.log('Found onetalk frame');

  // 提取数据
  const r = await ot.evaluate(() => {
    const d = window.__conversationListFullData__;
    if (!d || !Array.isArray(d)) return { err: 'nodata', type: typeof d };
    const now = Date.now();
    const newest = d.slice(0, 10).map(c => ({
      name: c.name, cid: c.cid, st: c.serviceType,
      time: c.lastContactTime ? new Date(c.lastContactTime).toISOString().slice(0,16) : '?',
      msg: c.latestMessage?.content?.slice(0,80) || '',
    }));
    return { total: d.length, newest };
  });

  console.log('Total conversations:', r.total);
  console.log('Newest 10:');
  for (const c of r.newest) {
    console.log(' ', c.time, c.name, c.st, '|', c.msg.slice(0,60));
  }

  // 搜索 Sek Sopha
  console.log('');
  console.log('Searching for Sek/Sopha...');
  const found = await ot.evaluate(() => {
    const d = window.__conversationListFullData__ || [];
    return d.filter(c => {
      const n = (c.name || '').toLowerCase();
      return n.includes('sek') || n.includes('soph') || n.includes('sop');
    }).map(c => ({ name: c.name, cid: c.cid, time: c.lastContactTime }));
  });
  console.log('Found:', found.length);
  for (const f of found) console.log(' ', f.name, f.cid, f.time);

})();
" 2>&1

