const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const pages = browser.contexts()[0].pages();
  const tmPage = pages.find(p => p.url().includes('talk/hub/tm'));
  if (!tmPage) { console.log('no TM hub page'); return; }

  // 遍历所有 frames
  const allFrames = tmPage.frames();
  let ot = null;
  for (const f of allFrames) {
    if (f.url().startsWith('https://onetalk.alibaba.com/')) { ot = f; break; }
    // 也检查子 frames
    const children = f.childFrames();
    for (const c of children) {
      if (c.url().startsWith('https://onetalk.alibaba.com/')) { ot = c; break; }
    }
    if (ot) break;
  }

  if (!ot) {
    console.log('onetalk not found. All frames:');
    for (const f of allFrames) console.log(' ', f.url().slice(0,100));
    return;
  }
  console.log('Found:', ot.url().slice(0,100));

  const r = await ot.evaluate(() => {
    const d = window.__conversationListFullData__ || [];
    const top10 = d.slice(0, 10).map(c => ({
      name: c.name, time: c.lastContactTime ? new Date(c.lastContactTime).toISOString().slice(0,16) : '?'
    }));
    const fuzzy = d.filter(c => {
      const n = (c.name || '').toLowerCase();
      return n.includes('sek') || n.includes('sop') || n.includes('sok');
    }).map(c => c.name);
    return { total: d.length, top10, fuzzy };
  });

  console.log('Total:', r.total);
  console.log('Top 10:');
  r.top10.forEach(c => console.log('  [' + c.time + '] ' + c.name));
  console.log('Fuzzy matches:', r.fuzzy.length > 0 ? r.fuzzy : 'NONE');

  if (r.fuzzy.length === 0) {
    // 搜所有名字含 s 开头短名字的（柬埔寨名字模式）
    const allNames = await ot.evaluate(() => {
      const d = window.__conversationListFullData__ || [];
      return d.map(c => c.name).sort();
    });
    console.log('Full name list saved, total unique: ' + [...new Set(allNames)].length);
  }
})();
