const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const pages = browser.contexts()[0].pages();
  let page = pages.find(p => p.url().includes('onetalk.alibaba.com'));
  if (!page) { console.log('No onetalk page found'); return; }

  // 1. 获取 Sek Sopha 的基本元数据
  const meta = await page.evaluate(() => {
    const d = window.__conversationListFullData__ || [];
    const c = d.find(c => c.name === 'Sek Sopha');
    if (!c) return { err: 'not found' };
    return {
      name: c.name,
      cid: c.cid,
      country: c.country,
      companyName: c.companyName,
      level: c.level,
      serviceType: c.serviceType,
      unreadCount: c.unreadCount,
      lastContactTime: c.lastContactTime ? new Date(c.lastContactTime).toISOString() : null,
      latestMessage: c.latestMessage,
      available: c.available,
    };
  });
  console.log('Meta:', JSON.stringify(meta, null, 2));

  if (meta.err) return;

  // 2. Install LWP and fetch chat history
  const cdpClient = await page.context().newCDPSession(page);

  // Install LWP
  await cdpClient.send('Runtime.evaluate', {
    expression: `
      (function() {
        var _send = WebSocket.prototype.send;
        var _ae = WebSocket.prototype.addEventListener;
        window.__lwpPending = {};
        window.__lwpSeq = 0;
        WebSocket.prototype.send = function(data) {
          if (!window.__lwpWs && this.readyState === 1) {
            window.__lwpWs = this;
            _ae.call(this, 'message', function(event) {
              try {
                var raw = typeof event.data === 'string' ? event.data : '';
                if (raw.indexOf('\"code\"') < 0) return;
                var parsed = JSON.parse(raw);
                var mid = parsed.headers && parsed.headers.mid;
                if (mid && window.__lwpPending[mid]) {
                  var p = window.__lwpPending[mid];
                  delete window.__lwpPending[mid];
                  p.resolve(parsed);
                }
              } catch(e) {}
            });
          }
          return _send.call(this, data);
        };
        window.__lwpRequest = function(lwpPath, body) {
          return new Promise(function(resolve, reject) {
            var ws = window.__lwpWs;
            if (!ws || ws.readyState !== 1) { reject(new Error('WS not ready')); return; }
            var mid = Date.now() + ' ' + (++window.__lwpSeq);
            var req = JSON.stringify({ lwp: lwpPath, headers: { mid: mid }, body: body });
            window.__lwpPending[mid] = { resolve: resolve, reject: reject };
            ws.send(req);
            setTimeout(function() {
              if (window.__lwpPending[mid]) { delete window.__lwpPending[mid]; reject(new Error('timeout')); }
            }, 30000);
          });
        };
        return 'ok';
      })()
    `,
    awaitPromise: false
  });

  console.log('Waiting for WS connection...');
  await new Promise(r => setTimeout(r, 5000));

  // Check WS
  const wsCheck = await page.evaluate('window.__lwpWs ? window.__lwpWs.url : null');
  console.log('WS:', wsCheck);

  // 3. Fetch messages
  const cid = meta.cid;
  console.log('Fetching messages for cid:', cid);

  const allMessages = [];
  let cursor = 9007199254740991;
  const MAX_PAGES = 10;
  const MSG_COUNT = 50;

  for (let p = 0; p < MAX_PAGES; p++) {
    const raw = await page.evaluate(async (args) => {
      try {
        const result = await window.__lwpRequest('/r/MessageManager/listUserMessages', [args.cid, false, args.cursor, args.count, false]);
        return JSON.stringify(result);
      } catch(e) {
        return JSON.stringify({ __error: e.message });
      }
    }, { cid, cursor, count: MSG_COUNT });

    await new Promise(r => setTimeout(r, 1500));

    if (!raw) break;
    let response;
    try { response = JSON.parse(raw); } catch(e) { break; }
    if (response.__error || response.code !== 200) { 
      console.log('  Response issue:', response.__error || response.code);
      break; 
    }

    const body = response.body;
    if (!body?.userMessageModels || body.userMessageModels.length === 0) break;

    allMessages.push(...body.userMessageModels);
    console.log('  Page ' + (p+1) + ': ' + body.userMessageModels.length + ' msgs (total: ' + allMessages.length + ')');

    if (body.userMessageModels.length < MSG_COUNT || !body.nextCursor) break;
    cursor = body.nextCursor;
  }

  console.log('Total messages:', allMessages.length);

  // 4. Print formatted messages
  console.log('');
  console.log('====== CHAT HISTORY ======');
  console.log('Customer:', meta.name);
  console.log('Country:', meta.country);
  console.log('CID:', meta.cid);
  console.log('');

  for (const msg of allMessages) {
    const sender = msg.message?.sender?.uid === '2500000853693@icbu' ? 'ME' : 'CUST';
    const time = new Date(msg.message?.createAt || 0).toISOString().slice(0, 19).replace('T', ' ');
    const content = msg.message?.content?.text?.content || '';
    console.log('[' + time + '] ' + sender + ': ' + content.slice(0, 500));
  }

})();
