/**
 * 抓取单个客户的聊天记录
 * 用法: node scripts/fetch_one_chat.js "Sek Sopha"
 */
const { chromium } = require('playwright');

async function main() {
  const targetName = process.argv[2];
  if (!targetName) { console.log('Usage: node scripts/fetch_one_chat.js "Customer Name"'); process.exit(1); }

  const browser = await chromium.connectOverCDP('http://localhost:9222');
  const pages = browser.contexts()[0].pages();
  let page = pages.find(p => p.url().includes('onetalk.alibaba.com'));
  if (!page) {
    console.log('No onetalk page found. Opening...');
    page = await browser.contexts()[0].newPage();
    await page.goto('https://onetalk.alibaba.com/message/weblitePWA.htm?relevanceAccountId=285526143&from=xiaoman', { waitUntil: 'domcontentloaded', timeout: 20000 }).catch(() => {});
    await new Promise(r => setTimeout(r, 5000));
  }

  // 1. Get customer metadata
  const meta = await page.evaluate((name) => {
    const d = window.__conversationListFullData__ || [];
    const c = d.find(c => c.name === name);
    if (!c) return { err: 'Customer not found: ' + name };
    return {
      name: c.name, cid: c.cid, country: c.country,
      companyName: c.companyName, level: c.level,
      serviceType: c.serviceType, unreadCount: c.unreadCount,
      lastContactTime: c.lastContactTime ? new Date(c.lastContactTime).toISOString() : null,
      latestMessage: c.latestMessage?.content,
    };
  }, targetName);

  if (meta.err) { console.log(meta.err); process.exit(1); }
  console.log('Customer:', meta.name);
  console.log('Country:', meta.country);
  console.log('CID:', meta.cid);
  console.log('Last contact:', meta.lastContactTime);

  // 2. Install LWP interceptor
  await page.evaluate(() => {
    const _send = WebSocket.prototype.send;
    const _ae = WebSocket.prototype.addEventListener;
    window.__lwpPending = {};
    window.__lwpSeq = 0;
    WebSocket.prototype.send = function(data) {
      if (!window.__lwpWs && this.readyState === 1) {
        window.__lwpWs = this;
        _ae.call(this, 'message', function(event) {
          try {
